export const VERIFY_CHANNEL_COUNTRIES: CountryListItem[] = VERIFY_COUNTRY_CODES.map((code) => ({
  code,
  name: VERIFY_COUNTRY_NAMES[code] ?? code,
  flag: getFlagEmoji(code),
  isPriority: VERIFY_PRIORITY_CODES.has(code),
}));

export const VERIFY_RATES_TABLE_COUNTRIES = VERIFY_CHANNEL_COUNTRIES.filter((country) => {
  const entry = VERIFY_CHANNEL_PRICING[country.code];
  return entry && (entry.smsRate !== null || entry.voiceRate !== null || entry.whatsappRate !== null);
});

export function getVerifyChannelPricing(code?: string | null): VerifyChannelPricingEntry {
  const normalizedCode = (code || "US").toUpperCase();
  return VERIFY_CHANNEL_PRICING[normalizedCode] ?? {
    smsRate: null,
    voiceRate: null,
    whatsappRate: VERIFY_WHATSAPP_DEFAULT,
  };
}

export function formatVerifyRate(code: string, rate: number | null, unit: "sms" | "min" | "conversation") {
  if (rate === null || rate === undefined) return "Not supported";
  const symbol = code.toUpperCase() === "IN" ? "₹" : "$";
  const decimals = code.toUpperCase() === "IN" && unit === "sms" ? 2 : 4;
  return `${symbol}${rate.toFixed(decimals)}/${unit}`;
}

export function getVerifyPricingLinks(code: string) {
  const normalizedCode = code.toUpperCase();
  const slug = normalizedCode.toLowerCase();
  return {
    sms: SMS_ROUTE_CODES.has(normalizedCode) ? `/sms/pricing/${slug}/` : `/sms/pricing/`,
    voice: VOICE_ROUTE_CODES.has(normalizedCode) ? `/voice/pricing/${slug}/` : `/voice/pricing/`,
    whatsapp: WHATSAPP_ROUTE_CODES.has(normalizedCode) ? `/whatsapp-message/pricing/${slug}/` : `/whatsapp-message/pricing/`,
  };
}

